def get_signing_key(token):
    """Get the signing key - supports both JWKS (asymmetric) and shared secret (symmetric)."""
    algorithm = app.config["JWT_ALGORITHM"]

    if algorithm.startswith("HS"):
        # Symmetric - use shared secret
        secret = app.config["JWT_SECRET"]
        if not secret:
            raise ValueError("JWT_SECRET must be set for HS* algorithms")
        if len(secret) < 32:
            raise ValueError("JWT_SECRET is too short - use at least 32 characters")
